-- Program: Fitness Influencer Challenge
-- Category: Content Creator/Influencer Fitness -> influencer
-- Priority: High
-- Durations: [4, 8, 12], Sessions: [5, 6]

-- Insert branded program
INSERT INTO branded_programs (
    name, description, category, difficulty_level,
    duration_weeks, sessions_per_week, split_type,
    goals, requires_gym, is_active
) VALUES (
    'Fitness Influencer Challenge',
    'Camera-ready physique blueprint focusing on the most photogenic muscle groups',
    'influencer',
    'all_levels',
    12,
    6,
    'custom',
    ARRAY['Maximize muscle hypertrophy', 'Time under tension']::text[],
    true,
    true
) ON CONFLICT (name) DO UPDATE SET
    description = EXCLUDED.description,
    category = EXCLUDED.category,
    difficulty_level = EXCLUDED.difficulty_level,
    duration_weeks = EXCLUDED.duration_weeks,
    sessions_per_week = EXCLUDED.sessions_per_week,
    split_type = EXCLUDED.split_type,
    goals = EXCLUDED.goals,
    requires_gym = EXCLUDED.requires_gym,
    updated_at = NOW();

-- Variant: Fitness Influencer Challenge - 4w 5x/wk
INSERT INTO program_variants (
    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    4,
    'Fitness Influencer Challenge - 4w 5x/wk',
    'influencer',
    5,
    60,
    ARRAY['Maximize muscle hypertrophy', 'Time under tension']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Fitness Influencer Challenge'
ON CONFLICT DO NOTHING;

